use std::net::UdpSocket;
use std::thread::sleep;
use std::time::Duration;

const TARGET_IP: &str = "127.0.0.1";
const PORT: u16 = 80;
const TIMEOUT_SECS: u32 = 1;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let socket = UdpSocket::bind("0.0.0.0:0")?;
    socket.set_read_timeout(Some(Duration::from_secs(TIMEOUT_SECS as u64)))?;

    let targets = vec![80, 443, 21];

    for port in targets {
        let target_addr = format!("{}:{}", TARGET_IP, port);
        println!("Checking port {} on {}. Sending packet...", port, TARGET_IP); 

        match socket.send_to(&[0xDE, 0xAD, 0xBE, 0xEF], &target_addr) {
            Ok(bytes_sent) => println!("  -> Sent {} bytes.", bytes_sent),
            Err(e) => eprintln!("  -> Error sending packet: {}", e),
        }

        let mut buf = [0u8; 1024];
        match socket.recv_from(&mut buf) {
            Ok((size, _src)) => {
                println!("  => Success! Received {} bytes response.", size);
            }
            Err(e) if e.kind() == std::io::ErrorKind::TimedOut => {
                println!("  => Timeout. Port appears closed or filtered.");
            }
            Err(e) => {
                eprintln!("  -> Failed to receive data: {}", e);
            }
        }
        sleep(Duration::from_millis(500));
    }

    Ok(()) 
}
